arguments.command:
cd /tmp/sv-031fb5e5c22e46f9ae0bbdebea1c1e90/symbols && \
echo "=== Looking up nearest dynamic symbols ===" && \
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo -n "PC $addr -> "
  # Find the nearest symbol below this address
  nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | awk -v target="$addr" '
    BEGIN { best_name="??"; best_addr=0; target_dec=strtonum(target) }
    /^[0-9a-f]/ {
      sym_addr = strtonum("0x"$1)
      if (sym_addr <= target_dec && sym_addr > best_addr) {
        best_addr = sym_addr
        best_name = $3
      }
    }
    END { printf "%s+0x%x\n", best_name, target_dec - best_addr }
  '
done

