arguments.command:
cd /tmp/sv-031fb5e5c22e46f9ae0bbdebea1c1e90/symbols && \
echo "=== Symbols near each PC ===" && \
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  target=$(printf "%d" "$addr")
  echo "--- PC $addr ---"
  nm -D --defined-only --numeric-sort libmonosgen-2.0.so 2>/dev/null | awk -v t="$target" '
    /^[0-9a-f]/ {
      a = strtonum("0x"$1)
      if (a <= t) { prev_addr=a; prev_name=$3 }
      if (a > t && !found) { next_addr=a; next_name=$3; found=1 }
    }
    END {
      printf "  before: %s @ 0x%x (+0x%x)\n", prev_name, prev_addr, t-prev_addr
      printf "  after:  %s @ 0x%x\n", next_name, next_addr
    }
  '
done

