arguments.command:
cd /tmp/sv-031fb5e5c22e46f9ae0bbdebea1c1e90/symbols && \
echo "=== Symbol sizes ===" && \
nm -D -S --defined-only --numeric-sort libmonosgen-2.0.so 2>/dev/null | awk '
  /^[0-9a-f]/ && NF>=4 {
    addr = strtonum("0x"$1)
    size = strtonum("0x"$2)
    name = $4
    # Check if any of our target addresses fall within this symbol
    targets[1]=0x222098; targets[2]=0x222234; targets[3]=0x19bac0; targets[4]=0x19bc14
    for (i=1; i<=4; i++) {
      if (addr <= targets[i] && (addr+size) > targets[i]) {
        printf "PC 0x%x -> %s+0x%x (sym @ 0x%x, size 0x%x)\n", targets[i], name, targets[i]-addr, addr, size
      }
    }
  }
'

